          intro: "useDebounce returns a debounced copy of a value that only updates after it stops changing for a given delay. Use it to throttle expensive work â€” search queries, autosave, live validation â€” off a fast-changing input. It ships as a copy-in hook from the registry under @/hooks/use-debounce.",
          code: "import { useDebounce } from '@/hooks/use-debounce';\n\nfunction Search() {\n  const [query, setQuery] = useState('');\n  const debouncedQuery = useDebounce(query, 300);\n\n  useEffect(() => {\n    // runs 300ms after the user stops typing\n    runSearch(debouncedQuery);\n  }, [debouncedQuery]);\n\n  return <input value={query} onChange={(e) => setQuery(e.target.value)} />;\n}",
